onClick:
{{
  (function() {
    const newStatus = wf_status_changer_widget.model.next_status;
    if (!newStatus) {
      navigateTo('Asset_Bookin_Page', { collectionId: appsmith.URL.queryParams.collectionId }, 'SAME_WINDOW');
      return;
    }
    storeValue('newStatus', newStatus).then(() => {
      qry_collection_status_update.run(
        function() {
          qry_collection_get.run();
          navigateTo('Asset_Bookin_Page', { collectionId: appsmith.URL.queryParams.collectionId }, 'SAME_WINDOW');
        },
        function(error) {
          showAlert('Failed to update status — ' + error.message, 'error');
        }
      );
    });
  })()
}}
